    labels = []
    if 'mse' in config and sum(config['mse']) > 0:
        labels.append('MSE')
        if mask is not None:
            functions.append(lambda x, y: F.mse_loss(x * mask, y))
        else:
            functions.append(lambda x, y: F.mse_loss(x, y))

